// frontend/src/App.js
import React, { useState, useEffect } from 'react';
import './App.css';

function App() {
  const [jobs, setJobs] = useState([]);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    user_type: 'worker',
    township: 'Soweto'
  });

  // Test backend connection
  const testBackend = async () => {
    try {
      const response = await fetch('http://localhost:5000/api/health');
      const data = await response.json();
      setMessage(`✅ Backend connected: ${data.status}`);
    } catch (error) {
      setMessage('❌ Backend not reachable. Start backend on port 5000');
    }
  };

  // Load jobs
  const loadJobs = async () => {
    setLoading(true);
    try {
      const response = await fetch('http://localhost:5000/api/jobs');
      const data = await response.json();
      if (data.success) {
        setJobs(data.data);
        setMessage(`✅ Loaded ${data.data.length} jobs`);
      }
    } catch (error) {
      setMessage('❌ Error loading jobs');
    }
    setLoading(false);
  };

  // Register user
  const registerUser = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const response = await fetch('http://localhost:5000/api/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      const data = await response.json();
      if (data.success) {
        setMessage(`✅ Registered: ${data.data.name}`);
        setFormData({ name: '', phone: '', user_type: 'worker', township: 'Soweto' });
      } else {
        setMessage(`❌ ${data.message}`);
      }
    } catch (error) {
      setMessage('❌ Registration failed');
    }
    setLoading(false);
  };

  // Handle input change
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  // Test on load
  useEffect(() => {
    testBackend();
    loadJobs();
  }, []);

  return (
    <div className="App">
      <header className="header">
        <h1>🏠 KasiConnect</h1>
        <p>Connecting Township Workers with Jobs</p>
      </header>

      <div className="container">
        {/* Status Message */}
        {message && (
          <div className="message-box">
            {message}
          </div>
        )}

        {/* Quick Stats */}
        <div className="stats-grid">
          <div className="stat-card">
            <h3>📊 Jobs Available</h3>
            <div className="stat-number">{jobs.length}</div>
          </div>
          <div className="stat-card">
            <h3>🔧 Workers</h3>
            <div className="stat-number">4+</div>
          </div>
          <div className="stat-card">
            <h3>🏪 Partner Shops</h3>
            <div className="stat-number">3</div>
          </div>
        </div>

        {/* Two Column Layout */}
        <div className="two-column">
          {/* Left Column - Registration */}
          <div className="card">
            <h2>📝 Register</h2>
            <form onSubmit={registerUser}>
              <div className="form-group">
                <label>Full Name:</label>
                <input
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleChange}
                  placeholder="John Doe"
                  required
                />
              </div>

              <div className="form-group">
                <label>Phone Number:</label>
                <input
                  type="tel"
                  name="phone"
                  value={formData.phone}
                  onChange={handleChange}
                  placeholder="27712345678"
                  required
                />
                <small>Format: 27712345678 (SA number)</small>
              </div>

              <div className="form-group">
                <label>I am a:</label>
                <select name="user_type" value={formData.user_type} onChange={handleChange}>
                  <option value="worker">👷 Worker (looking for jobs)</option>
                  <option value="client">🏠 Client (need help)</option>
                </select>
              </div>

              <div className="form-group">
                <label>Township:</label>
                <select name="township" value={formData.township} onChange={handleChange}>
                  <option value="Soweto">Soweto</option>
                  <option value="Alexandra">Alexandra</option>
                  <option value="Khayelitsha">Khayelitsha</option>
                  <option value="Tembisa">Tembisa</option>
                </select>
              </div>

              <button type="submit" className="btn-primary" disabled={loading}>
                {loading ? 'Registering...' : 'Register'}
              </button>
            </form>
          </div>

          {/* Right Column - Jobs List */}
          <div className="card">
            <h2>💼 Available Jobs</h2>
            <button onClick={loadJobs} className="btn-secondary" disabled={loading}>
              🔄 Refresh Jobs
            </button>

            {loading && <p className="loading">Loading...</p>}

            {jobs.length === 0 ? (
              <p className="no-data">No jobs available. Click refresh or add via API.</p>
            ) : (
              <div className="jobs-list">
                {jobs.map(job => (
                  <div key={job.id} className="job-item">
                    <h3>{job.title}</h3>
                    <p>{job.description}</p>
                    <div className="job-meta">
                      <span>📍 {job.township}</span>
                      <span>💰 R{job.budget_min} - R{job.budget_max}</span>
                      <span>👤 {job.client_name || 'Client'}</span>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* USSD Info */}
        <div className="ussd-card">
          <h2>📱 No Smartphone? Use USSD!</h2>
          <div className="ussd-code">
            <strong>Dial:</strong> *130*469#
          </div>
          <p>Works on any phone • No data needed • Free to use</p>
        </div>

        {/* Test Buttons */}
        <div className="test-buttons">
          <button onClick={testBackend} className="btn-test">
            🔍 Test Backend
          </button>
          <button onClick={() => window.open('http://localhost:5000/api/health')} className="btn-test">
            📡 API Health
          </button>
          <button onClick={() => window.open('http://localhost/phpmyadmin')} className="btn-test">
            🗄️ phpMyAdmin
          </button>
        </div>
      </div>
    </div>
  );
}

export default App;
